/// <summary>
/// When <c>JmgProductionFloorExecutionNewBusinessCardFlight</c> is enabled, the new design is applied to the business card grid (card list).
/// </summary>
/// <remarks>
/// The flight is controlled by entering the following in the flighting service (Carbon or similar):
/// "JmgProductionFloorExecutionNewBusinessCardFlight" to enable. This is only necessary when isEnabledByDefault() returns false.
/// "JmgProductionFloorExecutionNewBusinessCardFlight_KillSwitch" to disable. This overrules any enablement.
/// </remarks>
internal final class KPMGCommon_JmgProductionFloorExecutionNewBusinessCardFlight extends Flight
{
    static private KPMGCommon_JmgProductionFloorExecutionNewBusinessCardFlight singleton = new KPMGCommon_JmgProductionFloorExecutionNewBusinessCardFlight();

}
